-- Catálogo global: estructura oficial del Formulario 103 (SRI)
-- Transcrito de "SRI GUIA TECNICA/formulario103.xls" (Resolución NAC-DGERCGC16-00000125).
-- Es un catálogo GLOBAL (no lleva id_empresa): la estructura del formulario es la misma para todas las empresas.

CREATE TABLE IF NOT EXISTS sri_form103_casilleros (
    id              SERIAL PRIMARY KEY,
    casillero_base  VARCHAR(6),
    casillero_valor VARCHAR(6),
    descripcion     TEXT NOT NULL,
    seccion         VARCHAR(20) NOT NULL,
    orden           INTEGER NOT NULL,
    indent          SMALLINT NOT NULL DEFAULT 0,
    bold            BOOLEAN NOT NULL DEFAULT false,
    tipo            VARCHAR(20) NOT NULL DEFAULT 'concepto', -- concepto | subtotal | total | informativo
    formula_base    VARCHAR(60),
    formula_valor   VARCHAR(60),
    eliminado       BOOLEAN NOT NULL DEFAULT false,
    created_at      TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at      TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    deleted_at      TIMESTAMP,
    created_by      INTEGER,
    updated_by      INTEGER,
    deleted_by      INTEGER
);

TRUNCATE TABLE sri_form103_casilleros;


-- Reutilizar la tabla genérica de movimientos de declaración (ya usada por
-- Declaración IVA / Form 104) para el Form 103, distinguiendo por 'formulario'.
ALTER TABLE casilleros_declaracion_sri ADD COLUMN IF NOT EXISTS formulario VARCHAR(3) NOT NULL DEFAULT '104';
COMMENT ON COLUMN casilleros_declaracion_sri.formulario IS '104 = Declaración IVA, 103 = Declaración Retenciones en la Fuente';
